-- Payload Launcher

local sc = ""

init_dlsym()
sceMsgDialogTerminate() 

local PC_IP    = "192.168.1.114"
local LOG_PORT = 9027
local WEB_PORT = 9030

local function htons(p) return ((p << 8) | (p >> 8)) & 0xFFFF end
local function inet_addr(s)
    local a,b,c,d = s:match("(%d+)%.(%d+)%.(%d+)%.(%d+)")
    return (d << 24) | (c << 16) | (b << 8) | a
end

local function make_sockaddr_in(port, ip)
    local sa = malloc(16)
    for i = 0, 15 do write8(sa + i, 0) end
    write8(sa + 0, 16); write8(sa + 1, 2)
    write16(sa + 2, htons(port))
    if ip then write32(sa + 4, inet_addr(ip)) end
    return sa
end

local log_sock = create_socket(AF_INET, SOCK_DGRAM, 0)
local log_sa = make_sockaddr_in(LOG_PORT, PC_IP)

local function ulog(m)
    if log_sock >= 0 then syscall.sendto(log_sock, m.."\n", #m+1, 0, log_sa, 16) end
end
ulog("=== Payload Launcher ===")

if not sceKernelLoadStartModule then
    sceKernelLoadStartModule = func_wrap(dlsym(LIBKERNEL_HANDLE, "sceKernelLoadStartModule"))
end
local libUser = sceKernelLoadStartModule("libSceUserService.sprx", 0, 0, 0, 0, 0)
local getUserId = dlsym(libUser, "sceUserServiceGetInitialUser")
local uid_buf = malloc(4)
write32(uid_buf, 0)
if getUserId then func_wrap(getUserId)(uid_buf) end
local userId = read32(uid_buf)
ulog("userId=" .. tostring(userId))

local web_sock = create_socket(AF_INET, 1, 0) 
if web_sock >= 0 then
    local ba = make_sockaddr_in(WEB_PORT)
    local en = malloc(4)
    write32(en, 1)
    syscall.setsockopt(web_sock, 0xFFFF, 4, en, 4)
    syscall.bind(web_sock, ba, 16)
    syscall.listen(web_sock, 128)
    ulog("Web controller on port " .. WEB_PORT)
else
    ulog("Web socket failed!")
end

local html_body = [=[
<!doctype html><html><body><h1>Payload Launcher</h1><p>Use the DualSense to navigate the on-screen menu.</p></body></html>
]=]

local html_resp = "HTTP/1.1 200 OK\r\nContent-Type:text/html\r\nConnection:close\r\n\r\n" .. html_body
local html_len = #html_resp
local html_mem = malloc(html_len + 16)
write_buffer(html_mem, html_resp)
ulog("HTML: " .. html_len .. " bytes")



local ftp_srv = create_socket(AF_INET, 1, 0)
if ftp_srv >= 0 then
    local en = malloc(4); write32(en, 1)
    syscall.setsockopt(ftp_srv, 0xFFFF, 0x0004, en, 4)   -- SO_REUSEADDR
    syscall.setsockopt(ftp_srv, 0xFFFF, 0x0200, en, 4)    -- SO_REUSEPORT
    local ba = make_sockaddr_in(2121)
    local ret = syscall.bind(ftp_srv, ba, 16)
    ulog("ftp_srv fd=" .. tostring(ftp_srv) .. " bind=" .. tostring(ret))
    syscall.listen(ftp_srv, 128)
end

local ftp_data = create_socket(AF_INET, 1, 0)
if ftp_data >= 0 then
    local en = malloc(4); write32(en, 1)
    syscall.setsockopt(ftp_data, 0xFFFF, 0x0004, en, 4)
    syscall.setsockopt(ftp_data, 0xFFFF, 0x0200, en, 4)
    local ba = make_sockaddr_in(2122)
    local ret = syscall.bind(ftp_data, ba, 16)
    ulog("ftp_data fd=" .. tostring(ftp_data) .. " bind=" .. tostring(ret))
    syscall.listen(ftp_data, 128)
end

sc = sc:gsub("%s", "")
local bin = hex_to_binary(sc)
local JIT_SIZE = 0x80000
local bfd = jit_malloc(8)
local rwfd = jit_malloc(8)
local rxfd = jit_malloc(8)
local rwa = jit_malloc(8)  
local rxa = malloc(8)       
local nm = jit_malloc(8)
jit_write_buffer(nm, "nv4b")
jit_sceKernelJitCreateSharedMemory(nm, JIT_SIZE, 7, bfd)
jit_sceKernelJitCreateAliasOfSharedMemory(jit_read32(bfd), PROT_READ|PROT_WRITE, rwfd)
jit_sceKernelJitCreateAliasOfSharedMemory(jit_read32(bfd), PROT_READ|PROT_EXECUTE, rxfd)
jit_sceKernelJitMapSharedMemory(jit_read32(rwfd), PROT_READ|PROT_WRITE, rwa)
local rw = jit_read64(rwa)
local mfd = jit_send_recv_fd(jit_read32(rxfd), NEW_JIT_SOCK, NEW_MAIN_SOCK)
sceKernelJitMapSharedMemory(mfd, PROT_READ|PROT_EXECUTE, rxa)
local rx = read64(rxa)
local bfd_fd = jit_read32(bfd)
local rwfd_fd = jit_read32(rwfd)
local rxfd_fd = jit_read32(rxfd)
write_shellcode(rw, sc)
ulog("rw=" .. string.format("%x", rw) .. " rx=" .. string.format("%x", rx) .. " sz=" .. #bin)

-- FS helpers (usados mas abajo para cargar el .bin seleccionado)
local sceOpen2  = func_wrap(dlsym(LIBKERNEL_HANDLE, "sceKernelOpen"))
local sceRead2  = func_wrap(dlsym(LIBKERNEL_HANDLE, "sceKernelRead"))
local sceClose2 = func_wrap(dlsym(LIBKERNEL_HANDLE, "sceKernelClose"))

-- Lee una cadena C desde puntero de memoria
local function read_cstring(ptr)
    if not ptr or ptr == 0 then return "" end
    local t = {}
    for i = 0, 255 do
        local c = read8(ptr + i)
        if c == 0 then break end
        t[#t+1] = string.char(c)
    end
    return table.concat(t)
end

-- Carga un binario desde disco al JIT en rw+0x2000 (Lua tiene acceso RW al JIT)
local function load_bin_to_jit(path)
    local ok, err = pcall(function()
        if not (sceOpen2 and sceRead2 and sceClose2) then error("no fs funcs") end
        local fd = sceOpen2(path, 0, 0, 0, 0, 0)
        ulog("LOAD fd=" .. tostring(fd) .. " path=" .. path)
        if fd < 0 then error("open fail " .. tostring(fd)) end
        local CHUNK = 4096
        local buf = malloc(CHUNK)
        if buf == 0 then sceClose2(fd,0,0,0,0,0); error("malloc fail") end
        local goff = 0x2000
        local total = 0
        while total < 0x170000 do
            local n = sceRead2(fd, buf, CHUNK, 0, 0, 0)
            if n <= 0 then break end
            local t = {}
            local i = 0
            while i + 15 < n do
                t[#t+1] = string.pack("<I4I4I4I4",
                    read32(buf+i),     read32(buf+i+4),
                    read32(buf+i+8),   read32(buf+i+12))
                i = i + 16
            end
            while i + 3 < n do
                t[#t+1] = string.pack("<I4", read32(buf+i)); i = i + 4
            end
            while i < n do t[#t+1] = string.char(read8(buf+i)); i = i + 1 end
            jit_write_buffer(rw + goff, table.concat(t))
            goff = goff + n
            total = total + n
        end
        sceClose2(fd, 0, 0, 0, 0, 0)
        ulog("LOAD done bytes=" .. tostring(total))
        if total < 1024 then error("too small: " .. tostring(total)) end
    end)
    if not ok then ulog("LOAD err: " .. tostring(err)) end
    return ok
end

-- ext_args layout
--   +0x00  s64 status
--   +0x08  s64 step
--   +0x10  u32 frame_count / +0x14 _pad
--   +0x18  s32 log_fd / +0x1C s32 pad_fd
--   +0x20  u8  log_addr[16]
--   +0x30  u64 dbg[0]  web socket fd
--   +0x38  u64 dbg[1]  html_mem ptr
--   +0x40  u64 dbg[2]  html_len
--   +0x48  u64 dbg[3]  userId
--   +0x50  u64 dbg[4]  FTP ctrl fd
--   +0x58  u64 dbg[5]  FTP data fd
--   +0x60  u64 dbg[6]  cmd: 0=exit 1=load+run (set by launcher)
--   +0x68  u64 dbg[7]  ptr to selected path string (set by launcher)
local ext = malloc(0x80)
memset(ext, 0, 0x80)
write64(ext+0x00, 0xDEAD)
write32(ext+0x18, log_sock)
write32(ext+0x1C, -1)
for i=0,15 do write8(ext+0x20+i, read8(log_sa+i)) end
write64(ext+0x30, web_sock >= 0 and web_sock or -1)
write64(ext+0x38, html_mem)
write64(ext+0x40, html_len)
write64(ext+0x48, userId)
write64(ext+0x50, ftp_srv >= 0 and ftp_srv or -1)
write64(ext+0x58, ftp_data >= 0 and ftp_data or -1)
write64(ext+0x60, 0)   -- dbg[6]: cmd (launcher lo rellena al salir)
write64(ext+0x68, 0)   -- dbg[7]: path ptr (launcher lo rellena al seleccionar)

local current_ip = get_current_ip()
ulog("IP: " .. current_ip)
send_notification("Payload Launcher\nhttp://" .. current_ip .. ":" .. WEB_PORT)

-- Fase 1: lanzar el explorador visual (payload_launcher.c en rx+0x0)
func_wrap(rx)(EBOOT_BASE, SCE_KERNEL_DLSYM, ext)

-- Fase 2: el launcher devolvio cmd en dbg[6]
local cmd      = read64(ext+0x60)
local path_ptr = read64(ext+0x68)
ulog("Launcher cmd=" .. tostring(cmd) .. " ptr=" .. tostring(path_ptr))

if cmd == 1 and path_ptr ~= 0 then
    local path = read_cstring(path_ptr)
    ulog("Loading: " .. path)
    local loaded = load_bin_to_jit(path)
    if loaded then
        ulog("Jumping to rx+0x2000")
        -- Fase 3: saltar al payload cargado
        func_wrap(rx + 0x2000)(EBOOT_BASE, SCE_KERNEL_DLSYM, ext)
    else
        ulog("Load failed, no jump")
    end
else
    ulog("Launcher exited, cmd=" .. tostring(cmd))
end

-- Cleanup sockets so repeated launches don't inherit stale listeners/fds.
if ftp_srv and ftp_srv >= 0 then pcall(function() syscall.close(ftp_srv) end) end
if ftp_data and ftp_data >= 0 then pcall(function() syscall.close(ftp_data) end) end
if web_sock and web_sock >= 0 then pcall(function() syscall.close(web_sock) end) end
if log_sock and log_sock >= 0 then pcall(function() syscall.close(log_sock) end) end
if mfd and mfd >= 0 then pcall(function() syscall.close(mfd) end) end
if rxfd_fd and rxfd_fd >= 0 then pcall(function() syscall.close(rxfd_fd) end) end
if rwfd_fd and rwfd_fd >= 0 then pcall(function() syscall.close(rwfd_fd) end) end
if bfd_fd and bfd_fd >= 0 then pcall(function() syscall.close(bfd_fd) end) end

ulog("Done")
